# Simple Benchmark Runner for LLMs

Here's a clean, extensible design:

```python
# benchmark_runner.py

import yaml
from dataclasses import dataclass, field
from typing import Protocol, Any
from pathlib import Path


# --- Configuration ---

@dataclass
class LLMCandidate:
    """Represents a candidate LLM to benchmark."""
    name: str
    model_id: str
    config: dict = field(default_factory=dict)

    def __repr__(self):
        return f"LLM({self.name}, model={self.model_id})"


# --- Benchmark Protocol ---

class Benchmark(Protocol):
    """Protocol defining how to evaluate an LLM."""

    def run(self, candidate: LLMCandidate) -> dict[str, Any]:
        """Run benchmark on candidate and return scores."""
        ...

    def aggregate(self, scores: dict[str, Any]) -> float:
        """Convert raw scores into a single numeric score."""
        ...


# --- Default Benchmark Implementation ---

class SimpleBenchmark:
    """Example benchmark that simulates scoring."""

    def __init__(self, tasks: list[str]):
        self.tasks = tasks

    def run(self, candidate: LLMCandidate) -> dict[str, Any]:
        # In practice, you'd call the LLM API here
        # This is a placeholder that generates mock scores
        import random
        random.seed(hash(candidate.model_id) % 2**32)

        return {
            task: random.uniform(0.5, 1.0) 
            for task in self.tasks
        }

    def aggregate(self, scores: dict[str, Any]) -> float:
        return sum(scores.values()) / len(scores)


# --- Runner ---

class BenchmarkRunner:
    """Orchestrates benchmarking of multiple LLMs."""

    def __init__(
        self, 
        candidates: list[LLMCandidate],
        benchmark: Benchmark,
        output_path: Path = Path("benchmark_results.yaml")
    ):
        self.candidates = candidates
        self.benchmark = benchmark
        self.output_path = output_path

    def run_all(self) -> list[dict]:
        """Run benchmark on all candidates and return ranked results."""
        results = []

        for candidate in self.candidates:
            print(f"Running benchmark on {candidate.name}...")

            raw_scores = self.benchmark.run(candidate)
            aggregated_score = self.benchmark.aggregate(raw_scores)

            results.append({
                "candidate": candidate.name,
                "model_id": candidate.model_id,
                "raw_scores": raw_scores,
                "score": aggregated_score
            })

        # Sort by score descending
        results.sort(key=lambda x: x["score"], reverse=True)

        # Add rank
        for i, r in enumerate(results, 1):
            r["rank"] = i

        return results

    def save_results(self, results: list[dict]):
        """Write ranked results to config file."""
        output = {
            "benchmark_results": results,
