To build a practical benchmark runner, you need three components: a **Provider Wrapper** to handle different APIs, a **Scoring Logic** (using an LLM-as-a-judge or exact match), and a **State Manager** to update the config.

The following Python implementation uses a "Judge" model to score candidates and saves the results to a YAML file.

### 1. The Implementation

```python
import yaml
import json
import openai  # Generic client for OpenAI, Anthropic, or Local (Ollama)

class BenchmarkRunner:
    def __init__(self, config_path="models_config.yaml"):
        self.config_path = config_path
        self.config = self.load_config()

    def load_config(self):
        with open(self.config_path, 'r') as f:
            return yaml.safe_load(f)

    def save_results(self):
        # Sort models by score descending before saving
        self.config['models'].sort(key=lambda x: x.get('score', 0), reverse=True)
        with open(self.config_path, 'w') as f:
            yaml.dump(self.config, f, default_flow_style=False)

    def get_completion(self, model_name, prompt):
        # Logic to route to different providers (OpenAI, Anthropic, etc.)
        # Simplified here for demonstration
        client = openai.OpenAI(api_key=self.config['api_keys'].get(model_name))
        response = client.chat.completions.create(
            model=model_name,
            messages=[{"role": "user", "content": prompt}]
        )
        return response.choices[0].message.content

    def judge_output(self, prompt, candidate_output, rubric):
        """Uses a strong model (e.g., GPT-4o) to score the candidate 1-10."""
        judge_client = openai.OpenAI(api_key=self.config['api_keys']['judge'])
        judge_prompt = f"""
        Task: Score the response based on this rubric: {rubric}
        Original Prompt: {prompt}
        Model Response: {candidate_output}
        Return ONLY a JSON object: {{"score": <int>, "reasoning": "<string>"}}
        """
        response = judge_client.chat.completions.create(
            model="gpt-4o",
            response_format={"type": "json_object"},
            messages=[{"role": "system", "content": "You are an objective grader."},
                      {"role": "user", "content": judge_prompt}]
        )
        return json.loads(response.choices[0].message.content)

    def run_suite(self, test_cases):
        for model_entry in self.config['models']:
            model_name = model_entry['name']
            total_score = 0

            print(f"Testing {model_name}...")
            for test in test_cases:
                output = self.get_completion(model_name, test['prompt'])
                result = self.judge_output(test['prompt'], output, test['rubric'])
                total_score += result['score']

            # Update average score in config
            model_entry['score'] = round(total_score / len(test_cases), 2)

        self.save_results()

# --- Usage ---
if __name__ == "__main__":
    test_suite = [
        {"prompt": "Explain quantum physics to a 5-year-old.", "rubric": "Simplicity and accuracy."},
        {"prompt": "Write a python function to sort a list.", "rubric": "Code correctness and PEP8 style."}
    ]

    runner = BenchmarkRunner()
    runner.run_suite(test_suite)
